function wildcardMatching(tests) {
    let t = parseInt(tests[0]);
    for (let i = 1; i <= t * 2; i += 2) {
        let x = tests[i];
        let y = tests[i + 1];
        let match = true;
        for (let j = 0; j < x.length; j++) {
            if (x[j] !== '?' && y[j] !== '?' && x[j] !== y[j]) {
                match = false;
                break;
            }
        }
        console.log(match ? "Yes" : "No");
    }
}

